// jsPDF minimal pour Carbonely
window.jspdf = { jsPDF: jsPDF };

function jsPDF(orientation = 'portrait', unit = 'mm', format = 'a4') {
    this.texts = [];
    this.images = [];
    this.lines = [];
    this.fontSize = 12;
    this.font = 'helvetica';
    this.fontStyle = 'normal';
    this.textColor = '#000000';
    this.pageWidth = format === 'a4' ? 210 : 216; // mm
    this.pageHeight = format === 'a4' ? 297 : 279;
    this.x = 20;
    this.y = 20;
    this.lineHeight = this.fontSize * 1.15;
    this.pages = [{
        content: [],
        width: this.pageWidth,
        height: this.pageHeight
    }];
    this.currentPage = 0;

    this.setFontSize = function(size) {
        this.fontSize = size;
        this.lineHeight = size * 1.15;
        return this;
    };

    this.setFont = function(font, style) {
        this.font = font;
        this.fontStyle = style || 'normal';
        return this;
    };

    this.setTextColor = function(r, g, b) {
        if (typeof r === 'string') {
            this.textColor = r;
        } else if (g !== undefined && b !== undefined) {
            this.textColor = `rgb(${r},${g},${b})`;
        } else {
            this.textColor = `rgb(${r},${r},${r})`;
        }
        return this;
    };

    this.text = function(text, x, y, options) {
        if (Array.isArray(text)) {
            text.forEach((line, i) => {
                this.text(line, x, y + (i * this.lineHeight));
            });
            return this;
        }

        const page = this.pages[this.currentPage];
        page.content.push({
            type: 'text',
            text: text,
            x: x || this.x,
            y: y || this.y,
            fontSize: this.fontSize,
            font: this.font,
            color: this.textColor
        });

        if (!y) this.y += this.lineHeight;
        return this;
    };

    this.line = function(x1, y1, x2, y2) {
        const page = this.pages[this.currentPage];
        page.content.push({
            type: 'line',
            x1: x1,
            y1: y1,
            x2: x2,
            y2: y2,
            color: this.textColor
        });
        return this;
    };

    this.rect = function(x, y, width, height, style = 'S') {
        const page = this.pages[this.currentPage];
        page.content.push({
            type: 'rect',
            x: x,
            y: y,
            width: width,
            height: height,
            style: style,
            color: this.textColor
        });
        return this;
    };

    this.addImage = function(imgData, format, x, y, width, height, alias, compression) {
        const page = this.pages[this.currentPage];
        page.content.push({
            type: 'image',
            data: imgData,
            x: x,
            y: y,
            width: width,
            height: height || 0
        });
        return this;
    };

    this.addPage = function(format, orientation) {
        this.currentPage++;
        this.pages.push({
            content: [],
            width: this.pageWidth,
            height: this.pageHeight
        });
        this.x = 20;
        this.y = 20;
        return this;
    };

    this.save = function(filename = 'document.pdf') {
        // Create a simple PDF simulation
        const content = this.generatePDFContent();
        const blob = new Blob([content], { type: 'application/pdf' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = filename;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        return this;
    };

    this.output = function(type, options) {
        if (type === 'datauristring') {
            const content = this.generatePDFContent();
            return 'data:application/pdf;base64,' + btoa(content);
        }
        return this.generatePDFContent();
    };

    this.generatePDFContent = function() {
        let content = '%PDF-1.4\n';
        content += '1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n';
        content += '2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count ' + this.pages.length + ' >>\nendobj\n';

        // Page objects
        this.pages.forEach((page, index) => {
            const pageNum = 3 + index;
            content += pageNum + ' 0 obj\n';
            content += '<< /Type /Page /Parent 2 0 R ';
            content += '/MediaBox [0 0 ' + page.width + ' ' + page.height + '] ';
            content += '/Contents ' + (pageNum + this.pages.length) + ' 0 R >>\n';
            content += 'endobj\n';
        });

        // Content streams
        this.pages.forEach((page, index) => {
            const streamNum = 3 + this.pages.length + index;
            let streamContent = 'BT\n';
            
            page.content.forEach(item => {
                if (item.type === 'text') {
                    streamContent += '/' + item.font[0] + ' ' + item.fontSize + ' Tf\n';
                    streamContent += item.x + ' ' + (page.height - item.y) + ' Td\n';
                    streamContent += '(' + this.escapeText(item.text) + ') Tj\n';
                }
            });
            
            streamContent += 'ET\n';
            
            content += streamNum + ' 0 obj\n';
            content += '<< /Length ' + streamContent.length + ' >>\n';
            content += 'stream\n' + streamContent + 'endstream\n';
            content += 'endobj\n';
        });

        // Cross-reference table
        const startxref = content.length;
        content += 'xref\n0 ' + (4 + this.pages.length * 2) + '\n';
        content += '0000000000 65535 f \n';
        for (let i = 1; i < 4 + this.pages.length * 2; i++) {
            content += '0000000000 00000 n \n';
        }
        
        content += 'trailer\n<< /Size ' + (4 + this.pages.length * 2) + ' /Root 1 0 R >>\n';
        content += 'startxref\n' + startxref + '\n';
        content += '%%EOF';
        
        return content;
    };

    this.escapeText = function(text) {
        return text.replace(/[\(\)\\]/g, '\\$&');
    };

    this.from = function(element, options) {
        const self = this;
        return {
            set: function(opt) {
                Object.assign(options || {}, opt);
                return this;
            },
            save: function(filename) {
                // Use html2canvas if available
                if (typeof html2canvas !== 'undefined') {
                    html2canvas(element).then(canvas => {
                        const imgData = canvas.toDataURL('image/jpeg');
                        const pdf = new jsPDF();
                        pdf.addImage(imgData, 'JPEG', 10, 10, 180, 0);
                        pdf.save(filename || 'document.pdf');
                    });
                } else {
                    console.warn('html2canvas not available');
                    self.save(filename || 'document.pdf');
                }
            }
        };
    };
}

window.jsPDF = jsPDF;